root.sql:
select sc_lon_m_loan_card.loan_contract_no , sc_lon_m_loan_card.membership_no , pka_com_function.fp_get_member_name( sc_lon_m_loan_card.membership_no ) as memname , sc_lon_m_loan_card.loan_type , sc_lon_m_loan_card.interest_arrear , sc_lon_m_loan_card.old_interest_arrear
,sc_lon_m_rule.loan_type_description
from sc_lon_m_loan_card ,sc_lon_m_rule where sc_lon_m_rule.loan_type = sc_lon_m_loan_card.loan_type and sc_lon_m_loan_card.principal_balance = 0 and ( interest_arrear <> 0 or old_interest_arrear <> 0 )
